const diagnostics = {};

const toStr = (v) => String(v ?? '').trim();
const toNum = (v) => {
  const n = Number(v);
  return Number.isFinite(n) ? n : NaN;
};

const parseMaybeArray = (value) => {
  if (Array.isArray(value)) return value.map((v) => toStr(v)).filter(Boolean);
  const raw = toStr(value);
  if (!raw) return [];
  if (raw.startsWith('[') && raw.endsWith(']')) {
    try {
      const parsed = JSON.parse(raw);
      if (Array.isArray(parsed)) return parsed.map((v) => toStr(v)).filter(Boolean);
    } catch (_e) {
      // fallback to single string
    }
  }
  return [raw];
};

const normalize = (v) => toStr(v)
  .normalize('NFD')
  .replace(/[\u0300-\u036f]/g, '')
  .toLowerCase()
  .trim();

const safeItemsFirstNonEmpty = (names) => {
  for (const name of names) {
    try {
      const rows = $items(name, 0, 0).map((i) => i.json || {});
      diagnostics['count_' + name] = rows.length;
      if (rows.length > 0) return rows;
    } catch (e) {
      diagnostics['err_' + name] = toStr(e && e.message ? e.message : e);
    }
  }
  return [];
};

const owner = toStr($json.owner || 'oliversoft-tech');
const token = toStr(
  $json.github_token ||
  ($env && $env.GITHUB_TOKEN) ||
  (typeof process !== 'undefined' && process.env ? process.env.GITHUB_TOKEN : '')
);
if (!token) {
  throw new Error('[Build Governance Issue Jobs] github_token ausente no input e GITHUB_TOKEN ausente no environment.');
}

const detectTarget = (repoName) => {
  const n = normalize(repoName);
  if (!n) return null;
  if (n.includes('domain')) return { repo: 'fastroute-domain', key: 'domain' };
  if (n === 'api' || n.includes('fastroute-api') || n.includes('fastroute_api') || n.endsWith('-api')) return { repo: 'fastroute-api', key: 'api' };
  if (n.includes('mobile')) return { repo: 'fastroute-mobile-hybrid', key: 'mobile' };
  return null;
};

const repoRows = safeItemsFirstNonEmpty(['Load Repos Table', 'Load Repos Table1', 'Load Repos Table2']);
const changeRows = safeItemsFirstNonEmpty(['Upsert Change In Repo', 'Upsert Change In Repo1', 'Upsert Change In Repo2']);
const codeRows = safeItemsFirstNonEmpty(['Upsert Code Changes', 'Upsert Code Changes1', 'Upsert Code Changes2']);

diagnostics.repo_rows = repoRows.length;
diagnostics.change_rows = changeRows.length;
diagnostics.code_rows = codeRows.length;

const repoNameById = new Map();
for (const r of repoRows) {
  const id = toNum(r.id ?? r.repo_id ?? r['\uFEFFid']);
  const name = toStr(r.name || r.repo_name || r.repository || r.full_name);
  if (Number.isFinite(id) && name) repoNameById.set(id, name);
}

const snippetsByChangeId = new Map();
for (const cc of codeRows) {
  const changeId = toNum(cc.change_id);
  const code = toStr(cc.code);
  if (!Number.isFinite(changeId) || !code) continue;
  if (!snippetsByChangeId.has(changeId)) snippetsByChangeId.set(changeId, []);
  snippetsByChangeId.get(changeId).push(code);
}

const impactId = toStr($json.impact_analysis_id || 'na');
const jobs = [];

for (const c of changeRows) {
  const changeId = toNum(c.id ?? c.change_id);
  if (!Number.isFinite(changeId)) continue;

  const repoId = toNum(c.repo_id);
  const repoName = toStr(c.repo_name || repoNameById.get(repoId) || '');
  const target = detectTarget(repoName);
  if (!target) continue;

  const summary = toStr(c.change_summary || c.description || 'Change sem resumo');
  const testSteps = parseMaybeArray(c.test_steps || c.tests || c.testes);
  const acceptance = parseMaybeArray(c.acceptance_criteria || c.criterios_aceite);
  const risks = parseMaybeArray(c.change_risks || c.riscos || c.risks);
  const doubts = parseMaybeArray(c.change_doubts || c.duvidas || c.doubts);
  const snippets = [...new Set((snippetsByChangeId.get(changeId) || []).map((x) => toStr(x)).filter(Boolean))];

  const titleBase = `[Impact ${impactId}] Change #${changeId} - ${summary}`;
  const title = titleBase.length > 230 ? titleBase.slice(0, 230) : titleBase;

  const lines = [];
  lines.push('Issue automatica gerada pelo fluxo de Impact Analysis.');
  lines.push('');
  lines.push(`- impact_analysis_id: ${impactId}`);
  lines.push(`- change_id: ${changeId}`);
  lines.push(`- repo: ${target.repo}`);
  lines.push(`- source_repo_name: ${repoName || 'N/A'}`);
  lines.push('');
  lines.push('## Resumo da Mudanca');
  lines.push(summary || 'N/A');
  lines.push('');

  if (acceptance.length > 0) {
    lines.push('## Criterios de Aceite');
    for (const a of acceptance) lines.push(`- ${a}`);
    lines.push('');
  }

  if (testSteps.length > 0) {
    lines.push('## Passos de Teste');
    for (const t of testSteps) lines.push(`- ${t}`);
    lines.push('');
  }

  if (risks.length > 0) {
    lines.push('## Riscos');
    for (const r of risks) lines.push(`- ${r}`);
    lines.push('');
  }

  if (doubts.length > 0) {
    lines.push('## Duvidas');
    for (const d of doubts) lines.push(`- ${d}`);
    lines.push('');
  }

  lines.push('## Code Changes Sugeridas');
  if (snippets.length === 0) {
    lines.push('_Sem snippets em code_changes para este change._');
  } else {
    snippets.forEach((snippet, idx) => {
      lines.push(`### Snippet ${idx + 1}`);
      lines.push('```ts');
      lines.push(snippet);
      lines.push('```');
      lines.push('');
    });
  }

  jobs.push({
    owner,
    github_token: token,
    target_repo: target.repo,
    repo_key: target.key,
    impact_analysis_id: impactId,
    change_id: changeId,
    issue_title: title,
    issue_body: lines.join('\n').slice(0, 64000),
    issue_labels: ['governance-impact', 'needs-approval', 'impact-analysis'],
    snippets_count: snippets.length,
  });
}

if (jobs.length === 0) {
  throw new Error('[Build Governance Issue Jobs] nenhum job gerado. diagnostics=' + JSON.stringify(diagnostics));
}

return jobs.map((json) => ({ json }));

const jobs = $input.all().map((i) => i.json || {});
if (jobs.length === 0) {
  throw new Error('[Create Governance Issues (GitHub API)] nenhum job recebido.');
}

const toStr = (v) => String(v ?? '').trim();
const toArr = (v) => Array.isArray(v) ? v : [];

const asText = (value) => {
  if (value === undefined || value === null) return '';
  if (typeof value === 'string') return value;
  try { return JSON.stringify(value); } catch (_e) { return String(value); }
};

const parseBody = (body) => {
  if (body === undefined || body === null) return null;
  if (typeof body === 'object') return body;
  try { return JSON.parse(String(body)); } catch (_e) { return null; }
};

const inferStatus = (e, fallbackText) => {
  const direct = Number(
    e?.statusCode ||
    e?.status ||
    e?.httpCode ||
    e?.response?.statusCode ||
    e?.response?.status ||
    0
  );
  if (Number.isFinite(direct) && direct > 0) return direct;

  const text = asText(fallbackText || e?.message || '');
  const m = text.match(/status code\s*(\d{3})/i) || text.match(/\b(\d{3})\b/);
  if (m) {
    const n = Number(m[1]);
    if (Number.isFinite(n)) return n;
  }
  return 0;
};

const gh = async ({ method, url, token, body }) => {
  try {
    const resp = await this.helpers.httpRequest({
      method,
      url,
      headers: {
        Authorization: 'Bearer ' + token,
        Accept: 'application/vnd.github+json',
        'X-GitHub-Api-Version': '2022-11-28',
      },
      body,
      json: true,
    });

    return {
      ok: true,
      status: 200,
      text: asText(resp),
      json: resp,
    };
  } catch (e) {
    const bodyData = e?.response?.body ?? e?.message ?? e;
    const status = inferStatus(e, bodyData);
    return {
      ok: false,
      status,
      text: asText(bodyData),
      json: parseBody(bodyData),
    };
  }
};

const out = [];

for (const job of jobs) {
  const owner = toStr(job.owner);
  const repo = toStr(job.target_repo);
  const token = toStr(job.github_token);
  const issueTitle = toStr(job.issue_title);
  const issueBody = toStr(job.issue_body);
  const labels = toArr(job.issue_labels).map((l) => toStr(l)).filter(Boolean);

  if (!owner || !repo || !token || !issueTitle) {
    throw new Error('[Create Governance Issues (GitHub API)] job invalido: owner/repo/token/title ausentes');
  }

  // de-dup simples por titulo em issues abertas
  const listResp = await gh({
    method: 'GET',
    url: 'https://api.github.com/repos/' + owner + '/' + repo + '/issues?state=open&per_page=100',
    token,
  });

  if (!listResp.ok || !Array.isArray(listResp.json)) {
    throw new Error('[Create Governance Issues (GitHub API)] falha ao listar issues em ' + repo + ': ' + listResp.status + ' ' + (listResp.text || '').slice(0, 300));
  }

  const existing = listResp.json.find((it) => !it.pull_request && toStr(it.title) === issueTitle);
  if (existing) {
    out.push({
      json: {
        status: 'already_exists',
        owner,
        repo,
        issue_url: toStr(existing.html_url),
        issue_number: Number(existing.number || 0) || null,
        issue_title: issueTitle,
        change_id: job.change_id,
        impact_analysis_id: job.impact_analysis_id,
      }
    });
    continue;
  }

  const createResp = await gh({
    method: 'POST',
    url: 'https://api.github.com/repos/' + owner + '/' + repo + '/issues',
    token,
    body: {
      title: issueTitle,
      body: issueBody,
      labels,
    },
  });

  if (!createResp.ok) {
    throw new Error('[Create Governance Issues (GitHub API)] falha ao criar issue em ' + repo + ': ' + createResp.status + ' ' + (createResp.text || '').slice(0, 400));
  }

  out.push({
    json: {
      status: 'created',
      owner,
      repo,
      issue_url: toStr(createResp.json && createResp.json.html_url),
      issue_number: Number((createResp.json && createResp.json.number) || 0) || null,
      issue_title: issueTitle,
      change_id: job.change_id,
      impact_analysis_id: job.impact_analysis_id,
    }
  });
}

return out;
